function renderBankChart() {
  const chart = document.getElementById("bank-chart");
  if (!chart || typeof Plotly === "undefined") return;

  const x = bankData.map(d => d["№"]);

  const traceGerzog = {
    x,
    y: bankData.map(d => d["Банк друга"]),
    mode: "lines+markers",
    name: "Gerzog",
    line: { width: 3 },
    marker: { size: 8 },
    customdata: bankData.map(d => [d["Матч"], d["Профит друга"], d["Тур"]]),
    hovertemplate:
      "<b>Gerzog</b><br>" +
      "Матч №%{x}<br>" +
      "%{customdata[0]}<br>" +
      "Тур: %{customdata[2]}<br>" +
      "Банк: %{y}<br>" +
      "Профит: %{customdata[1]:+d}<extra></extra>"
  };

  const traceYukon = {
    x,
    y: bankData.map(d => d["Твой банк"]),
    mode: "lines+markers",
    name: "Yukon",
    line: { width: 3 },
    marker: { size: 8 },
    customdata: bankData.map(d => [d["Матч"], d["Твой профит"], d["Тур"]]),
    hovertemplate:
      "<b>Yukon</b><br>" +
      "Матч №%{x}<br>" +
      "%{customdata[0]}<br>" +
      "Тур: %{customdata[2]}<br>" +
      "Банк: %{y}<br>" +
      "Профит: %{customdata[1]:+d}<extra></extra>"
  };

  const layout = {
    paper_bgcolor: "rgba(0,0,0,0)",
    plot_bgcolor: "rgba(255,255,255,.55)",
    font: { family: "Georgia, Times New Roman, serif", size: 14 },
    margin: { l: 58, r: 26, t: 30, b: 58 },
    hovermode: "closest",
    legend: { orientation: "h", x: 0, y: 1.08 },
    xaxis: {
      title: "Матч по порядку",
      dtick: 1,
      gridcolor: "rgba(115,106,94,.18)",
      zeroline: false
    },
    yaxis: {
      title: "Банк",
      gridcolor: "rgba(115,106,94,.18)",
      zeroline: false
    },
    shapes: [
      {
        type: "line",
        xref: "paper", x0: 0, x1: 1,
        yref: "y", y0: 1000, y1: 1000,
        line: { color: "#1c1a17", width: 1, dash: "dash" }
      },
      {
        type: "line",
        xref: "x", x0: 23.5, x1: 23.5,
        yref: "paper", y0: 0, y1: 1,
        line: { color: "#736a5e", width: 1, dash: "dash" }
      }
    ],
    annotations: [
      {
        xref: "paper", x: 0.01,
        yref: "y", y: 1000,
        text: "Стартовый банк",
        showarrow: false,
        yshift: 12
      },
      {
        xref: "x", x: 23.6,
        yref: "paper", y: 1,
        text: "Второй тур",
        showarrow: false,
        xanchor: "left",
        yshift: 14
      }
    ]
  };

  Plotly.newPlot(chart, [traceGerzog, traceYukon], layout, {
    responsive: true,
    displaylogo: false,
    modeBarButtonsToRemove: ["lasso2d", "select2d"]
  });
}

document.addEventListener("DOMContentLoaded", renderBankChart);
